var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배는? 아직도 못 찾은 거야?","JPN":"先輩は？　まだ見つかっていないの？","ENG":"Where's Shiyoon? You haven't found him yet?","TWN":"前輩呢？還是沒找到人嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 지난 주말 이후로 주시윤 씨의 흔적은 오리무중이에요.","JPN":"はい。先週末からアキヤマさんの行方は五里霧中です。","ENG":"I'm afraid not. He vanished without a trace, gone since last weekend.","TWN":"還沒，周時雲從上週末開始就行蹤不明。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"미나 양이 주시윤 씨를 마지막으로 봤다던 헬리포트는 큰 싸움이라도 난 것처럼 파괴되어 있었어요.","JPN":"ミナさんが最後にアキヤマさんを見たヘリポートは、大規模戦闘でもあったかのように破壊されていました。","ENG":"The heliport where he was last seen was in shambles, as if a big fight occurred.","TWN":"米娜你最後一次看到周時雲的直升機場，就像經歷第三次世界大戰一樣像個廢墟。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"주변에 설치된 CCTV들도 강력한 침식파에 노출된 것처럼 데이터가 모두 망가진 상태였고요.","JPN":"周辺の防犯カメラも強力な侵食波を受けたかのように、全てのデータが破損していました。","ENG":"I checked all the CCTVs nearby, but the data had been corrupted, as if it was exposed to Corruption Rays.","TWN":"周圍裝設的監視器，也像暴露在出強烈侵蝕波當中一樣，資料全都毀損。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"최선을 다해 찾고 있지만……. 아직까지는 수사에 이렇다 할 진전이 없네요.","JPN":"最善を尽くして捜索していますが……まだこれといった進展はありませんね。","ENG":"We're trying our best... But we haven't had much progress yet.","TWN":"我們已經盡力去找，但……目前還沒有進展。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럴 수가…….","JPN":"そんな……","ENG":"Dang...","TWN":"怎麼會這樣……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"안 되겠어! 나라도 직접 가서……!","JPN":"やっぱりこのままじゃダメ！　私が直接……！","ENG":"Alright, that's it. I'll just go there myself and...","TWN":"不行！我要自己去找……!"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"쓸데없는 짓은 그만두세요, 미나 양.","JPN":"無駄な行動はやめてください、ミナさん。","ENG":"I wouldn't waste your energy.","TWN":"米娜，請你不要輕舉妄動。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 짓이라니!","JPN":"無駄ってどういうこと！？","ENG":"How could you call this a waste?!","TWN":"什麼輕舉妄動！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님은 나보다 선배랑 더 오래 일했잖아. 그런데 걱정도 안 돼?","JPN":"副社長は私よりも先輩との付き合いが長いでしょう？　心配にならないの？","ENG":"You've worked with Shiyoon much longer than I have. Aren't you even a bit worried?","TWN":"副總你和前輩共事的時間比我還久，難道你都不擔心前輩嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 무슨 수로 시윤 군을 찾겠다는 거죠?","JPN":"それで、どうやってアキヤマ君を探すつもりですか？","ENG":"So how do you think you'll find him, exactly?","TWN":"所以你打算怎麼找到他？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마 이 넓은 도시를 혼자서 헤집고 다니겠다는 건가요?","JPN":"まさか、この広い都市を一人で手当たり次第探すとでも？","ENG":"You're not thinking of rummaging through this huge city by yourself, are you?","TWN":"這個城市這麼大，你打算自己一個人去找嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇지만…… 이렇게 기다려 봤자 아무 소식도 없잖아!","JPN":"でも……こうして待っているばかりじゃ何も進まないじゃない！","ENG":"But... Sitting around like this won't get us anywhere!","TWN":"我只是……我們這樣等也沒有任何消息不是嗎！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조바심을 낸다고 사라진 시윤 군이 갑자기 나타나진 않습니다.","JPN":"焦ったところで消えたアキヤマ君が突然戻ってくることはありません。","ENG":"Neither will getting antsy.","TWN":"就算我著急，時雲也不會因此就突然出現。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금은 믿고 기다려 보죠. 전문 인력들이 수사를 맡고 있으니까요.","JPN":"捜査は専門家に任せて、今は信じて待ちましょう。","ENG":"For now, let's try to be patient. We've got professionals on the case.","TWN":"既然都已經派人出去找，我們現在能做的就是等待。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래요. 저희도 최선을 다해서 찾아 볼게요.","JPN":"そうですよ。私たちも全力で捜索します。","ENG":"Indeed. We'll also try our best to find him.","TWN":"沒錯，我們也會盡全力去找的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어쨌거나 리플레이서 사태 때 그 난리를 같이 겪었던 사이잖아요.","JPN":"なんだかんだ、リプレイサー事件のあの大騒ぎを一緒に乗り越えた仲ですから。","ENG":"After all, we went through thick and thin during that Replacers fiasco.","TWN":"畢竟我們也在克隆集團事件中一起並肩作戰過的嘛！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"본청에서 인력도 더 배정해 준다고 했으니까, 조만간 단서가 나올 거예요.","JPN":"本庁も人員を追加補充すると言っているので、近いうちに手がかりが見つかると思いますよ。","ENG":"Top brass said they'd assign more personnel to the search effort, so we should find a lead soon.","TWN":"總部那邊說會再加派人手去找，說不定很快就會有好消息！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};